Different ways to create functions:

**Function Declaration:**
```javascript
function greet(name) {
  return 'Hello, ' + name;
}

// Hoisted - can be called before declaration
console.log(greet('Alice')); // Works!
```

**Function Expression:**
```javascript
const greet = function(name) {
  return 'Hello, ' + name;
};

// Not hoisted - must be declared first
```

**Arrow Function:**
```javascript
const add = (a, b) => a + b;
const square = x => x * x;
const sayHello = () => 'Hello!';

// Multi-line arrow function
const calculate = (a, b) => {
  const sum = a + b;
  return sum * 2;
};
```

**When to Use:**
- Declaration: General functions, need hoisting
- Expression: Callbacks, avoid hoisting
- Arrow: Short functions, preserve 'this'

Understand variable visibility:

**Global Scope:**
```javascript
let globalVar = 'I am global';

function showGlobal() {
  console.log(globalVar); // Accessible
}
```

**Function Scope (var):**
```javascript
function testVar() {
  if (true) {
    var x = 10; // Function-scoped
  }
  console.log(x); // 10 (accessible)
}
```

**Block Scope (let/const):**
```javascript
function testLet() {
  if (true) {
    let y = 20; // Block-scoped
  }
  console.log(y); // Error! Not accessible
}
```

**Scope Chain:**
```javascript
let outer = 'global';

function outerFunc() {
  let outer = 'outer';

  function innerFunc() {
    let inner = 'inner';
    console.log(inner); // 'inner'
    console.log(outer); // 'outer'
    console.log(globalVar); // 'global'
  }

  innerFunc();
}
```

**Best Practice:**
- Use `const` by default
- Use `let` when reassignment needed
- Avoid `var` in modern JavaScript

Functions that remember their environment:

**What is a Closure?**
A closure gives you access to an outer function's scope from an inner function.

**Basic Closure:**
```javascript
function createCounter() {
  let count = 0;

  return function() {
    count++;
    return count;
  };
}

const counter = createCounter();
console.log(counter()); // 1
console.log(counter()); // 2
console.log(counter()); // 3
```

**Practical Use Case:**
```javascript
function createMultiplier(multiplier) {
  return function(number) {
    return number * multiplier;
  };
}

const double = createMultiplier(2);
const triple = createMultiplier(3);

console.log(double(5)); // 10
console.log(triple(5)); // 15
```

**Data Privacy:**
```javascript
function createBankAccount() {
  let balance = 0;

  return {
    deposit: function(amount) {
      balance += amount;
      return balance;
    },
    getBalance: function() {
      return balance;
    }
  };
}

const account = createBankAccount();
account.deposit(100);
console.log(account.getBalance()); // 100
// balance is not accessible directly
```

Functions that take or return functions:

**Callback Functions:**
```javascript
function processArray(arr, callback) {
  const result = [];
  for (let item of arr) {
    result.push(callback(item));
  }
  return result;
}

const numbers = [1, 2, 3, 4];
const doubled = processArray(numbers, x => x * 2);
console.log(doubled); // [2, 4, 6, 8]
```

**Built-in Higher-Order Functions:**
```javascript
let numbers = [1, 2, 3, 4, 5];

// map - transform each element
let squared = numbers.map(x => x * x);

// filter - keep elements that pass test
let evens = numbers.filter(x => x % 2 === 0);

// reduce - combine elements
let sum = numbers.reduce((acc, x) => acc + x, 0);

// forEach - execute function on each
numbers.forEach(x => console.log(x));

// find - get first match
let found = numbers.find(x => x > 3);

// some/every - test conditions
let hasEven = numbers.some(x => x % 2 === 0);
let allPositive = numbers.every(x => x > 0);
```

**Chaining Methods:**
```javascript
let result = numbers
  .filter(x => x % 2 === 0)
  .map(x => x * 2)
  .reduce((acc, x) => acc + x, 0);
```

JavaScript ES6 introduced class syntax for object-oriented programming.

**Class Declaration:**
```javascript
class Person {
  constructor(name, age) {
    this.name = name;
    this.age = age;
  }

  greet() {
    return `Hello, my name is ${this.name}`;
  }
}

const person = new Person('Alice', 25);
console.log(person.greet()); // "Hello, my name is Alice"
```

**Inheritance:**
```javascript
class Animal {
  constructor(name) {
    this.name = name;
  }

  speak() {
    return `${this.name} makes a sound`;
  }
}

class Dog extends Animal {
  constructor(name, breed) {
    super(name);
    this.breed = breed;
  }

  speak() {
    return `${this.name} barks`;
  }
}

const dog = new Dog('Buddy', 'Golden Retriever');
console.log(dog.speak()); // "Buddy barks"
```

**Getters and Setters:**
```javascript
class Rectangle {
  constructor(width, height) {
    this._width = width;
    this._height = height;
  }

  get area() {
    return this._width * this._height;
  }

  set width(value) {
    if (value > 0) {
      this._width = value;
    }
  }
}
```

**Static Methods:**
```javascript
class MathHelper {
  static add(a, b) {
    return a + b;
  }
}

console.log(MathHelper.add(5, 3)); // 8

Handle operations that take time using async/await and Promises.

**Promises:**
```javascript
const fetchData = () => {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      resolve('Data loaded!');
    }, 1000);
  });
};

fetchData().then(data => console.log(data));
```

**Async/Await:**
```javascript
async function getData() {
  try {
    const response = await fetch('https://api.example.com/data');
    const data = await response.json();
    console.log(data);
  } catch (error) {
    console.error('Error:', error);
  }
}
```

**Fetch API:**
```javascript
// GET request
fetch('https://api.example.com/users')
  .then(response => response.json())
  .then(data => console.log(data))
  .catch(error => console.error(error));

// POST request
fetch('https://api.example.com/users', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({ name: 'Alice', age: 25 })
})
  .then(response => response.json())
  .then(data => console.log(data));
```

**Best Practices:**
- Use async/await for cleaner code
- Always handle errors with try/catch
- Use Promise.all() for parallel requests

Organize code into reusable modules.

**Exporting from a module:**
```javascript
// utils.js
export const add = (a, b) => a + b;
export const multiply = (a, b) => a * b;

export default function greet(name) {
  return `Hello, ${name}`;
}
```

**Importing in another module:**
```javascript
// main.js
import greet, { add, multiply } from './utils.js';

console.log(add(5, 3)); // 8
console.log(multiply(4, 3)); // 12
console.log(greet('Alice')); // "Hello, Alice"
```

**Named vs Default Exports:**
```javascript
// Named export - can have multiple
export const PI = 3.14159;
export function calculateArea(radius) {
  return PI * radius * radius;
}

// Default export - only one per module
export default class Calculator {
  // ...
}
```

**Dynamic Imports:**
```javascript
async function loadModule() {
  const module = await import('./utils.js');
  module.add(5, 3);
}
```
